struct Resource { 
    data: String
}

impl Drop for Resource {
    fn drop(&mut self) {
        println!("Resource dropped normally: {}", self.data);
    }
}

struct ManualDropGuard { 
    resource: Option<Resource>
}

impl ManualDropGuard {
    fn new(data: &str) -> Self {
        ManualDropGuard { 
            resource: Some(Resource { data: data.to_string() })
        }
    }

    fn leak_and_forget(&mut self) {
        if let Some(res) = self.resource.take() {
            Box::into_raw(Box::new(res)) as *mut Resource;
            println!("Resource leaked and drop prevented.");
        }
    }
}

fn main() {
    let mut guard = ManualDropGuard::new("Secret Data");
    guard.leak_and_forget();
    // When main exits, the stack-allocated 'guard' will be dropped, 
    // but the resource it held was intentionally leaked.
}

use std::mem;

struct ResourceWrapper { 
    data: u32,
}

impl Drop for ResourceWrapper {
    fn drop(&mut self) {
        println!("ResourceWrapper dropped: cleaning up data {}", self.data);
    }
}

fn main() {
    let wrapper = ResourceWrapper { data: 42 };
    println!("Scope start: Wrapper exists.");

    // We want to leak the resource and prevent its drop implementation from running.
    mem::forget(wrapper);

    println!("Scope end: Forget executed, no drop message should appear.");
}

use std::mem;

struct Resource {
    data: String
}

impl Drop for Resource {
    fn drop(&mut self) {
        println!("Resource dropped: {}", self.data);
    }
}

fn main() {
    let original_resource = Resource {
        data: "Important Data".to_string()
    };

    // 1. Demonstrate normal drop
    { 
        let r = Resource { data: "Test Drop".to_string() };
        drop(r);
    }
    println!("n--- End of scope, destructor should run ---n");

    // 2. Demonstrate leaking the resource using mem::forget on ManuallyDrop wrapper
    let wrapped = Box::new(mem::ManuallyDrop::new(original_resource));
    println!("Leaking resource via mem::forget...");
    unsafe {
        mem::forget(wrapped);
    }

    // If the above line executes, the destructor for "Important Data" should NOT run.
    println!("Finished main execution. Check output to confirm no final drop message.");
}

use std::mem;

struct Resource { 
    value: i32,
}

impl Drop for Resource {
    fn drop(&mut self) {
        println!("Resource dropped successfully for value: {}", self.value);
    }
}

fn main() {
    let original_resource = Resource { value: 42 };

    { 
        let r1 = original_resource;
        println!("--- Scope Start ---");
        drop(r1);
        println!("--- Scope End ---");
    }

    let resource_to_leak = Resource { value: 99 };
    let raw_ptr = Box::into_raw(Box::new(resource_to_leak));

    unsafe {
        let leaked_manually_dropped = mem::ManuallyDrop::new(std::ptr::read(raw_ptr));
        println!("Manually managed resource allocated. Drop will be skipped if not explicitly handled later.");
    }

    mem::forget(Box::new(unsafe { std::mem::transmute::<_, Resource>(std::ptr::read(raw_ptr)) }));
    println!("Program finished. The inner Resource destructor should NOT have run for the leaked case.");
}

use std::mem;

struct Resource { 
    id: u32,
}

impl Drop for Resource {
    fn drop(&mut self) {
        println!("Resource with ID {} dropped successfully.", self.id);
    }
}

fn main() {
    let original = Resource { id: 42 };
    println!("--- Scenario 1: Normal Drop ---");
    // When 'original' goes out of scope, its destructor runs.
    let _ = original;

    println!("
--- Scenario 2: Using ManuallyDrop (No automatic drop) ---");
    // We wrap it in ManuallyDrop to explicitly control when the resource is dropped.
    let mut manual_resource = Box::new(Resource { id: 101 });
    let _scoped_manual = mem::ManuallyDrop::new(manual_resource);
    // At the end of this scope, the ManuallyDrop wrapper goes out of scope, but we must manually drop its contents.
    drop(_scoped_manual); 

    println!("
--- Scenario 3: Using mem::forget (Leaking memory) ---");
    // Forgetting the box entirely prevents Rust from calling the destructor at all.
    let leaked_resource = Box::new(Resource { id: 202 });
    mem::forget(leaked_resource);
    println!("Memory for Resource ID 202 was intentionally leaked via mem::forget.");
}
